// Passthrough: if an input is connected, forward it unchanged.
if (inputs.Length > 0 && inputs[0] != null)
    return inputs[0]!;

// No input: return a transparent buffer.
var size = context.TileSize;
var buffer = new PixelBuffer(size, size);
buffer.ParallelForEachPixel((x, y) => buffer.SetPixel(x, y, 0f, 0f, 0f, 0f));
return buffer;
